// Los datos de entrada vienen del nodo anterior
const items = $input.all();

// Extraer los datos JSON de cada item
const data = items.map(item => item.json);

// Función para combinar tickets
function combinarTickets(data) {
  const mapa = new Map();

  // Agrupar por ticketID
  data.forEach(item => {
    // Obtener el ID (puede estar en ticketID o ticketId)
    const id = item.ticketID || item.ticketId;

    if (!id) return;

    if (!mapa.has(id)) {
      mapa.set(id, {});
    }

    // Combinar todas las propiedades
    const objetoActual = mapa.get(id);
    Object.keys(item).forEach(key => {
      if (key === 'ticketId') {
        objetoActual.ticketID = item[key];
      } else {
        objetoActual[key] = item[key];
      }
    });
  });

  return Array.from(mapa.values());
}

// Procesar los datos
const resultado = combinarTickets(data);

// Retornar en el formato que n8n espera
return resultado.map(item => ({
  json: item
}));

try {
  // Accedemos al objeto que sale del nodo "Send and Wait"
  const item = items[0].json;

