  const text = item.data && item.data.text ? item.data.text : "";

  const regex = /TKT-\d{8}-\d{4}/;
  const match = text.match(regex);

  return {
    ticketId: match ? match[0] : null
  };
} catch (error) {
  return { ticketId: null };
}

