  throw new Error('La propiedad "output" no existe o no es un string válido');
}

// Parsear el string JSON interno
let parsedOutput;
try {
  parsedOutput = JSON.parse(inputData.output);
} catch (error) {
  throw new Error(`Error al parsear el JSON de output: ${error.message}`);
